707         Known = Known.unionWith(LHSRange.toKnownBits());
708       }
709       if (Pred == ICmpInst::ICMP_UGT || Pred == ICmpInst::ICMP_UGE) {
710         // X & Y u> C     -> X u> C && Y u> C
711         // X nuw- Y u> C  -> X u> C
712         if (match(LHS, m_c_And(m_V, m_Value())) ||
